70	const sumItemBasePremiums = (items: Item[]): number => {
71	  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
72	  const nonComponents = items.filter((i) => !COMPONENT_TYPES.has(i.type));
73	  const nonComponentSum = nonComponents.reduce((sum, item) => sum + itemBasePremium(item), 0);
74	  let componentSum = 0;
75	  if (components.length === 3) {
76	    componentSum = BLOCK_PREMIUM;
77	  } else {
78	    componentSum = components.reduce((sum, item) => sum + itemBasePremium(item), 0);
79	  }
80	  return nonComponentSum + componentSum;
81	};
